SEARCH_ORDERS_TOOL = {
    "name": "search_orders",
    "description": (
        "Search customer orders by status and optional date range. "
        "Returns order id, customer name, total, and created date. "
        "status must be one of: pending, processing, shipped, delivered, cancelled."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "status": {"type": "string", "enum": ["pending", "processing", "shipped", "delivered", "cancelled"]},
            "since_date": {"type": "string", "description": "ISO 8601 date, e.g. 2025-01-01. Optional."},
            "limit": {"type": "integer", "minimum": 1, "maximum": 50}
        },
        "required": ["status"]
    }
}

def search_orders(status: str, since_date: str | None = None, limit: int = 20) -> dict:
    sql = """
        SELECT o.id, c.name AS customer_name, o.total_cents, o.created_at
        FROM orders o
        JOIN customers c ON c.id = o.customer_id
        WHERE o.status = :status
    """
    params: dict = {"status": status, "limit": limit}
    if since_date:
        sql += " AND o.created_at >= :since_date"
        params["since_date"] = since_date
    sql += " ORDER BY o.created_at DESC LIMIT :limit"
    try:
        rows = _query(sql, params)
    except Exception:
        return {"error": "SERVICE_UNAVAILABLE", "message": "Database query failed.", "retryable": True}
    return {
        "results": [
            {
                "id": r["id"],
                "customer": r["customer_name"],
                "total_dollars": r["total_cents"] / 100,
                "created": str(r["created_at"])[:10],
            }
            for r in rows
        ],
        "count": len(rows),
        "status_filter": status,
    }

def get_order(order_id: str) -> dict:
    rows = _query(
        "SELECT o.id, c.name, o.status, o.total_cents, o.created_at "
        "FROM orders o JOIN customers c ON c.id = o.customer_id "
        "WHERE o.id = :id",
        {"id": order_id},
    )
    if not rows:
        return {
            "error": "NOT_FOUND",
            "message": f"Order {order_id!r} does not exist.",
            "retryable": False,
        }
    r = rows[0]
    return {
        "id": r["id"],
        "customer": r["name"],
        "status": r["status"],
        "total_dollars": r["total_cents"] / 100,
        "created": str(r["created_at"])[:10],
    }

ALLOWED_ORDER_STATUSES = {"processing", "shipped", "delivered", "cancelled"}

UPDATE_ORDER_STATUS_TOOL = {
    "name": "update_order_status",
    "description": (
        "Update the status of an existing order. "
        "Valid transitions: processing -> shipped, shipped -> delivered, "
        "pending/processing/shipped -> cancelled."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "order_id": {"type": "string"},
            "new_status": {"type": "string", "enum": list(ALLOWED_ORDER_STATUSES)}
        },
        "required": ["order_id", "new_status"]
    }
}

def update_order_status(order_id: str, new_status: str) -> dict:
    if new_status not in ALLOWED_ORDER_STATUSES:
        return {
            "error": "VALIDATION_ERROR",
            "message": f"new_status must be one of {sorted(ALLOWED_ORDER_STATUSES)}.",
            "retryable": False,
        }
    try:
        with _ENGINE.begin() as conn:  # auto-commit on success, rollback on exception
            result = conn.execute(
                text("UPDATE orders SET status = :s, updated_at = now() WHERE id = :id"),
                {"s": new_status, "id": order_id},
            )
        if result.rowcount == 0:
            return {"error": "NOT_FOUND", "message": f"Order {order_id!r} not found.", "retryable": False}
        return {"order_id": order_id, "new_status": new_status, "updated": True}
    except Exception:
        return {"error": "SERVICE_UNAVAILABLE", "message": "Update failed.", "retryable": True}

def summary_orders_by_status() -> dict:
    rows = _query(
        "SELECT status, COUNT(*) AS count, SUM(total_cents) AS total_cents "
        "FROM orders GROUP BY status ORDER BY count DESC",
        {},
    )
    return {
        "summary": [
            {
                "status": r["status"],
                "count": r["count"],
                "total_dollars": (r["total_cents"] or 0) / 100,
            }
            for r in rows
        ]
    }

def list_tables() -> dict:
    rows = _query(
        "SELECT table_name FROM information_schema.tables "
        "WHERE table_schema = 'public' ORDER BY table_name",
        {},
    )
    return {"tables": [r["table_name"] for r in rows]}

def describe_table(table_name: str) -> dict:
    # Allowlist tables to prevent information_schema leakage
    ALLOWED_TABLES = {"orders", "customers", "products", "order_items"}
    if table_name not in ALLOWED_TABLES:
        return {
            "error": "NOT_FOUND",
            "message": f"Table {table_name!r} not found or not accessible.",
            "retryable": False,
        }
    rows = _query(
        "SELECT column_name, data_type, is_nullable "
        "FROM information_schema.columns "
        "WHERE table_schema = 'public' AND table_name = :t ORDER BY ordinal_position",
        {"t": table_name},
    )
    return {
        "table": table_name,
        "columns": [
            {"name": r["column_name"], "type": r["data_type"], "nullable": r["is_nullable"] == "YES"}
            for r in rows
        ],
    }

from sqlalchemy.exc import IntegrityError, OperationalError

def insert_customer(name: str, email: str) -> dict:
    try:
        with _ENGINE.begin() as conn:
            result = conn.execute(
                text("INSERT INTO customers (name, email) VALUES (:n, :e) RETURNING id"),
                {"n": name, "e": email},
            )
            new_id = result.fetchone()[0]
        return {"id": new_id, "name": name, "email": email}
    except IntegrityError:
        return {
            "error": "CONFLICT",
            "message": f"A customer with email {email!r} already exists.",
            "retryable": False,
        }
    except OperationalError:
        return {
            "error": "SERVICE_UNAVAILABLE",
            "message": "Database connection failed. Try again.",
            "retryable": True,
        }
